const PDFDocument = require('pdfkit');
const fs = require('fs');
const path = require('path');

const OUTPUT_DIR = path.join(__dirname, '..', 'public', 'sample-data');

function addCover(doc, title, subtitle, version, date) {
  doc.moveDown(6);
  doc.fontSize(28).font('Helvetica-Bold').fillColor('#003366').text(title, { align: 'center' });
  doc.moveDown(1);
  doc.fontSize(16).font('Helvetica').fillColor('#666666').text(subtitle, { align: 'center' });
  doc.moveDown(3);
  doc.fontSize(11).fillColor('#333333');
  doc.text(`Version: ${version}`, { align: 'center' });
  doc.text(`Effective Date: ${date}`, { align: 'center' });
  doc.text('Classification: Internal — Confidential', { align: 'center' });
  doc.moveDown(2);
  doc.fontSize(10).fillColor('#999999').text('HDFC Bank Limited — Retail Assets Group', { align: 'center' });
  doc.text('Synthetic Training Data — GenAI Playground', { align: 'center' });
  doc.addPage();
}

function addTOC(doc, chapters) {
  doc.fontSize(18).font('Helvetica-Bold').fillColor('#003366').text('Table of Contents');
  doc.moveDown(1);
  chapters.forEach((ch, i) => {
    doc.fontSize(11).font('Helvetica').fillColor('#333333').text(`${i + 1}. ${ch.title}`, { continued: false });
  });
  doc.addPage();
}

function addChapter(doc, num, title, content) {
  doc.fontSize(16).font('Helvetica-Bold').fillColor('#003366').text(`${num}. ${title}`);
  doc.moveDown(0.5);
  doc.moveTo(doc.x, doc.y).lineTo(doc.x + 480, doc.y).stroke('#003366');
  doc.moveDown(0.5);
  content.forEach(section => {
    if (section.heading) {
      doc.fontSize(12).font('Helvetica-Bold').fillColor('#003366').text(section.heading);
      doc.moveDown(0.3);
    }
    if (section.body) {
      doc.fontSize(10).font('Helvetica').fillColor('#333333').text(section.body, { lineGap: 3 });
      doc.moveDown(0.5);
    }
    if (section.bullets) {
      section.bullets.forEach(b => {
        doc.fontSize(10).font('Helvetica').fillColor('#333333').text(`  •  ${b}`, { lineGap: 2 });
      });
      doc.moveDown(0.5);
    }
    if (section.table) {
      section.table.forEach((row, ri) => {
        const bold = ri === 0;
        doc.fontSize(9).font(bold ? 'Helvetica-Bold' : 'Helvetica').fillColor('#333333').text(row, { lineGap: 2 });
      });
      doc.moveDown(0.5);
    }
  });
  doc.addPage();
}

function createPDF(filename, folder, title, subtitle, chapters) {
  const dir = path.join(OUTPUT_DIR, folder);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  const filepath = path.join(dir, filename);
  const doc = new PDFDocument({ size: 'A4', margins: { top: 60, bottom: 60, left: 60, right: 60 }, bufferPages: true });
  const stream = fs.createWriteStream(filepath);
  doc.pipe(stream);
  addCover(doc, title, subtitle, '3.2', 'April 2026');
  addTOC(doc, chapters);
  chapters.forEach((ch, i) => addChapter(doc, i + 1, ch.title, ch.content));
  doc.end();
  return new Promise(resolve => stream.on('finish', () => { console.log(`  Created: ${filepath}`); resolve(); }));
}

